namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Call this periodically or let the background generate them.
    /// </summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Your report is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "Someone commented on your post.",
            "Your subscription will renew soon.",
            "A new update is available.",
        };

        // ~30% chance of generating a notification each tick
        if (Random.Shared.Next(100) < 30)
        {
            lock (_lock)
            {
                var msg = messages[Random.Shared.Next(messages.Length)];
                _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
            }
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    // Runs during prerender AND when interactive — loads initial data both times,
    // but the second run (interactive) will see the same data so no flash.
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    // Only called once the component is fully interactive in the browser.
    // This is where we start polling — never during static SSR.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate new notifications arriving server-side
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

