+<h1>
+    Notifications
+    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
+</h1>
+
+@if (_notifications.Count == 0)
+{
+    <p><em>No notifications yet.</em></p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <span>@n.Message</span>
+                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<BlazorApp.Services.Notification> _notifications = new();
+    private CancellationTokenSource? _cts;
+    private int _lastSeenId;
+
+    // Runs during prerender AND when interactive — loads initial data both times,
+    // but the second run (interactive) will see the same data so no flash.
+    protected override void OnInitialized()
+    {
+        _notifications = NotificationService.GetAll();
+        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
+    }
+
+    // Only called once the component is fully interactive in the browser.
+    // This is where we start polling — never during static SSR.
+    protected override Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+
+        return Task.CompletedTask;
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+            }
+            catch (OperationCanceledException)
+            {
+                break;
+            }
+
+            // Simulate new notifications arriving server-side
+            NotificationService.SimulateIncoming();
+
+            var newer = NotificationService.GetSince(_lastSeenId);
+            if (newer.Count > 0)
+            {
+                _notifications.AddRange(newer);
+                _lastSeenId = newer.Max(n => n.Id);
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
+
